public function index(Request $request) { $bulan = $request->bulan ?? date('m'); $tahun = $request->tahun ?? date('Y'); $historibulanini = Presensi::where( 'nik', Auth::guard('karyawan')->user()->nik ) ->whereMonth('tgl_presensi', $bulan) ->whereYear('tgl_presensi', $tahun) ->orderBy('tgl_presensi', 'desc') ->get(); return view('laporan.index', compact( 'historibulanini', 'bulan', 'tahun' )); } public function exportpdf(Request $request) { $bulan = $request->bulan ?? date('m'); $tahun = $request->tahun ?? date('Y'); $historibulanini = Presensi::where( 'nik', Auth::guard('karyawan')->user()->nik ) ->whereMonth('tgl_presensi', $bulan) ->whereYear('tgl_presensi', $tahun) ->orderBy('tgl_presensi', 'asc') ->get(); $pdf = Pdf::loadView( 'laporan.exportpdf', compact( 'historibulanini', 'bulan', 'tahun' ) ); return $pdf->stream( 'laporan-absensi-' . $bulan . '-' . $tahun . '.pdf' ); }